  let inv_rot_scale = mat3x3f(
      vec3f(m[0].x, m[1].x, m[2].x) * invSqLen,
      vec3f(m[0].y, m[1].y, m[2].y) * invSqLen,
      vec3f(m[0].z, m[1].z, m[2].z) * invSqLen
  );

